@st.cache_data
def load_data_40():
    """Load 40 data dari embed internal"""
    df = pd.DataFrame(_RAW_40)
    df['Soil Moisture (%)'] = pd.to_numeric(df['Soil Moisture (%)'], errors='coerce').round(1)
    df['Suhu (°C)']         = pd.to_numeric(df['Suhu (°C)'],         errors='coerce').round(1)
    if 'Status Pompa' not in df.columns:
        df['Status Pompa'] = df['Keterangan'].apply(lambda x: 'Menyala' if str(x)=='Kering' else 'Mati')
    return df[['No','Hari','Tanggal','Jam','HST','Soil Moisture (%)','Suhu (°C)','Keterangan','Status Pompa']]

