def style_tabel(val):
    if val in ['Kering', 'Menyala']:
        return 'background-color: rgba(248,113,113,0.12); color: #f87171; font-weight: 700;'
    elif val in ['Ideal', 'Mati']:
        return 'background-color: rgba(93,190,60,0.12); color: #5dbe3c; font-weight: 700;'
    elif val in ['Basah']:
        return 'background-color: rgba(96,165,250,0.12); color: #60a5fa; font-weight: 700;'
    return ''


