def make_fig(figsize=(14, 4)):
    fig, ax = plt.subplots(figsize=figsize, facecolor='#08120a')
    ax.set_facecolor('#0e1f0b')
    for sp in ax.spines.values():
        sp.set_edgecolor('#1e3d18')
    ax.tick_params(colors='#4a7a38', labelsize=8)
    ax.grid(True, color='#152a10', linestyle=':', alpha=0.6, linewidth=0.7)
    return fig, ax


