if "ptr_1440" not in st.session_state:
    st.session_state.ptr_1440 = 1   # Index awal mulai jalannya jendela linier 1440
if "ptr_40" not in st.session_state:
    st.session_state.ptr_40 = 1    # Index awal mulai jalannya jendela primer 40

@st.fragment(run_every=1.0)
def render_dashboard(m_val, s_val):
    # ── [1] KONTROL DETAK UTAMA POINTER TIMELINE (SERENTAK) ──
    max_1440 = len(df_berwarna) if not df_berwarna.empty else 1440
    if st.session_state.ptr_1440 < max_1440:
        st.session_state.ptr_1440 += 1
    else:
        st.session_state.ptr_1440 = 1  # Reset otomatis jika siklus 1440 data habis

    max_40 = len(df_40) if not df_40.empty else 40
    if st.session_state.ptr_40 < max_40:
        st.session_state.ptr_40 += 1
    else:
        st.session_state.ptr_40 = 1    # Reset otomatis jika siklus 40 data habis

    curr_ptr_1440 = st.session_state.ptr_1440
    curr_ptr_40   = st.session_state.ptr_40

    container_animasi = st.empty()

    # ── [2] PEMOTONGAN DATA TIMELINE BERDASARKAN DETAK POINTER (1440 DATA) ──
    if not df_berwarna.empty:
        df_timeline_1440 = df_berwarna.iloc[:curr_ptr_1440].copy()
        m_arr_base = df_timeline_1440['Soil Moisture (%)'].values.astype(float)
        s_arr_base = df_timeline_1440['Suhu (°C)'].values.astype(float)
        x_arr_base = df_timeline_1440['No'].values
    else:
        # Cadangan generator data acak jika df_berwarna kosong
        x_arr_base = np.arange(1, curr_ptr_1440 + 1)
        m_arr_base = np.random.uniform(55, 75, size=curr_ptr_1440)
        s_arr_base = np.random.uniform(26, 33, size=curr_ptr_1440)
        df_timeline_1440 = pd.DataFrame({
            'No': x_arr_base, 'Hari': 'Live', 'Tanggal': 'Real-time',
            'Jam': '00:00', 'HST': 10, 'Soil Moisture (%)': m_arr_base, 'Suhu (°C)': s_arr_base,
            'Keterangan': 'Ideal', 'Status Pompa': 'Mati'
        })

    # ── [3] PEMOTONGAN DATA TIMELINE BERDASARKAN DETAK POINTER (40 DATA) ──
    if not df_40.empty:
        df_timeline_40 = df_40.iloc[:curr_ptr_40].copy()
        m40_base = df_timeline_40['Soil Moisture (%)'].values.astype(float)
        s40_base = df_timeline_40['Suhu (°C)'].values.astype(float)
        x40_base = df_timeline_40['No'].values
    else:
        x40_base = np.arange(1, curr_ptr_40 + 1)
        m40_base = np.random.uniform(55, 72, size=curr_ptr_40)
        s40_base = np.random.uniform(27, 32, size=curr_ptr_40)
        df_timeline_40 = pd.DataFrame({
            'No': x40_base, 'Hari': 'Live', 'Tanggal': 'Live',
            'Jam': '00:00', 'HST': 10, 'Soil Moisture (%)': m40_base, 'Suhu (°C)': s40_base,
            'Keterangan': 'Ideal', 'Status Pompa': 'Mati'
        })

    # ── [4] INTEGRASI NILAI LIVE DARI SLIDER KE DATA PALING UJUNG SECARA SINKRON ──
    m_val_curr = float(np.round(m_arr_base[-2] + (m_val - m_arr_base[-2]) * 1.0, 1)) if len(m_arr_base) > 1 else m_val
    s_val_curr = float(np.round(s_arr_base[-2] + (s_val - s_arr_base[-2]) * 1.0, 1)) if len(s_arr_base) > 1 else s_val

    m_arr_base[-1] = m_val_curr
    s_arr_base[-1] = s_val_curr
    m40_base[-1]   = m_val_curr
    s40_base[-1]   = s_val_curr

    with container_animasi.container():
        # ── METRIC CARDS ──
        pompa_aktif = m_val_curr < 60
        mc_pompa    = "mc-red" if pompa_aktif else "mc-green"
        pompa_txt   = "⚡ ACTIVE (ON)"   if pompa_aktif else "🔒 STANDBY (OFF)"
        pompa_color = "val-red"          if pompa_aktif else "val-green"
        m_color     = "val-red"          if m_val_curr < 60 else ("val-blue" if m_val_curr > 70 else "val-green")

        st.markdown(f"""
        <div class="metric-row">
          <div class="metric-card mc-green">
            <div class="metric-label">💧 Kelembapan Tanah</div>
            <div class="metric-value {m_color}">{m_val_curr}<span class="unit">%</span></div>
            <div class="metric-sub">Threshold aman: 60 – 70%</div>
          </div>
          <div class="metric-card mc-yellow">
            <div class="metric-label">🌡️ Suhu Udara</div>
            <div class="metric-value val-yellow">{s_val_curr}<span class="unit">°C</span></div>
            <div class="metric-sub">Rentang optimal: 25 – 35 °C</div>
          </div>
          <div class="metric-card {mc_pompa}">
            <div class="metric-label">🔌 Status Relay Pompa</div>
            <div class="metric-status {pompa_color}">{pompa_txt}</div>
            <div class="metric-sub">Otomatis berdasarkan sensor moisture</div>
          </div>
        </div>
        """, unsafe_allow_html=True)

        # ══════════════════════════════════════════════════════════════
        #  TABEL A — VIEW TIMELINE BERJALAN 1440 DATA BERWARNA
        # ══════════════════════════════════════════════════════════════
        st.markdown("""
        <div class="sec-header" style="margin-top:8px;">
          <div class="sec-header-icon">📋</div>
          <div>
            <div class="sec-header-title">Dataset Deret Waktu IoT — 1440 Data</div>
            <div class="sec-header-sub">Data rekaman sensor terupdate secara kontinu dari berkas excel</div>
          </div>
        </div>
        """, unsafe_allow_html=True)

        st.markdown(f"""
        <div class="tabel-header-row">
          <span class="tabel-title">Log Sensor · Mengalir Serentak Menuju Titik Ke-{curr_ptr_1440}</span>
        </div>
        """, unsafe_allow_html=True)

        cols_show = ['No','Hari','Tanggal','Jam','HST','Soil Moisture (%)','Suhu (°C)','Keterangan','Status Pompa']
        display_rows_1440 = 20
        if len(df_timeline_1440) > display_rows_1440:
            df_table_window = df_timeline_1440.iloc[-display_rows_1440:].copy()
        else:
            df_table_window = df_timeline_1440.copy()

        start_row_1440 = df_table_window['No'].iloc[0] if not df_table_window.empty else 0
        end_row_1440 = df_table_window['No'].iloc[-1] if not df_table_window.empty else 0
        st.markdown(f"<div style='font-size:12px; color:#7ab860; margin-bottom:8px;'>Realtime tabel: menampilkan baris terakhir {start_row_1440}–{end_row_1440} dari {curr_ptr_1440} data.</div>", unsafe_allow_html=True)

        styled_b = (df_table_window[cols_show].style
                    .format({'Soil Moisture (%)': '{:.1f}', 'Suhu (°C)': '{:.1f}'})
                    .map(style_tabel, subset=['Keterangan','Status Pompa']))
        st.dataframe(styled_b, height=320, use_container_width=True, hide_index=True)

        # ── GRAFIK A REAL-TIME (DATA 1440 BERTAHAP) ──
        st.markdown("""
        <div class="sec-header" style="margin-top:20px;">
          <div class="sec-header-icon">📈</div>
          <div>
            <div class="sec-header-title">Grafik Real-Time — Data 1440 Bertahap</div>
            <div class="sec-header-sub">Menampilkan seluruh rekaman 1440 data yang datang secara real-time</div>
          </div>
        </div>
        """, unsafe_allow_html=True)

        st.markdown(f"<div style='font-size:12px; color:#7ab860; margin-bottom:12px;'>Data yang muncul: <strong>{curr_ptr_1440}</strong> dari <strong>{max_1440}</strong> titik.</div>", unsafe_allow_html=True)

        window_1440 = len(x_arr_base)
        x_w1 = x_arr_base[-window_1440:]
        m_w1 = m_arr_base[-window_1440:]
        s_w1 = s_arr_base[-window_1440:]

        fig, ax1 = make_fig(figsize=(14, 4))
        ax1.set_xlabel('Indeks Waktu (Urutan Data Sensor)', color='#3d6e30', fontsize=9)
        ax1.set_ylabel('Soil Moisture (%)', color='#5dbe3c', fontsize=10, labelpad=8)
        ax1.plot(x_w1, m_w1, color='#5dbe3c', linewidth=1.8, alpha=0.9)
        ax1.fill_between(x_w1, m_w1, alpha=0.08, color='#5dbe3c')
        ax1.axhline(60, color='#f87171', linestyle='--', alpha=0.75, linewidth=1.4)
        ax1.axhline(70, color='#60a5fa', linestyle='--', alpha=0.55, linewidth=1.0)
        ax1.tick_params(axis='y', labelcolor='#5dbe3c', labelsize=8)
        ax1.scatter(x_w1[-1], m_w1[-1], color='#5dbe3c', s=100, zorder=5, edgecolors='#08120a', linewidths=1.5)

        ax2 = ax1.twinx()
        ax2.set_ylabel('Suhu (°C)', color='#f59e0b', fontsize=10, labelpad=8)
        ax2.plot(x_w1, s_w1, color='#f59e0b', linewidth=1.2, alpha=0.7, linestyle=':')
        ax2.scatter(x_w1[-1], s_w1[-1], color='#f59e0b', s=50, zorder=5)
        ax2.set_ylim(max(min(s_w1) - 2, 15), max(s_w1) + 2)
        ax2.tick_params(axis='y', labelcolor='#f59e0b', labelsize=8)
        for sp in ax2.spines.values(): sp.set_edgecolor('#1e3d18')
        ax2.text(
            1.02, 0.80,
            'Garis merah: Batas Moisture 60%\nGaris biru putus-putus: Batas Moisture 70%',
            transform=ax2.transAxes,
            ha='left', va='top',
            fontsize=8,
            color='#f8fafc',
            bbox=dict(facecolor='#08120a', alpha=0.75, edgecolor='#3d6e30', boxstyle='round,pad=0.3')
        )

        fig.tight_layout(pad=1.5)
        st.pyplot(fig)
        plt.close(fig)

        m_mean = round(float(np.mean(m_arr_base)), 1)
        m_min  = round(float(np.min(m_arr_base)),  1)
        m_max  = round(float(np.max(m_arr_base)),  1)

        st.markdown(f"""
        <div class="chart-legend">
          <div class="legend-item"><div class="legend-line" style="background:#5dbe3c;"></div>Soil Moisture (%)</div>
          <div class="legend-item"><div class="legend-line" style="background:#f59e0b; border-top: 2px dotted #f59e0b; background:none;"></div>Suhu (°C)</div>
        </div>
        <div class="chart-stat-row">
          <div class="chart-stat-box"><div class="chart-stat-label">Rata-rata Moisture (Akumulasi)</div><div class="chart-stat-val">{m_mean}%</div></div>
          <div class="chart-stat-box"><div class="chart-stat-label">Min Moisture</div><div class="chart-stat-val">{m_min}%</div></div>
          <div class="chart-stat-box"><div class="chart-stat-label">Max Moisture</div><div class="chart-stat-val">{m_max}%</div></div>
        </div>
        """, unsafe_allow_html=True)

        st.markdown('<hr class="ag-divider">', unsafe_allow_html=True)

        # ══════════════════════════════════════════════════════════════
        #  TABEL B — VIEW TIMELINE BERJALAN 40 DATA PRIMER
        # ══════════════════════════════════════════════════════════════
        st.markdown("""
        <div class="sec-header">
          <div class="sec-header-icon">📋</div>
          <div>
            <div class="sec-header-title">Data Lapangan — 40 Baris Data Primer</div>
            <div class="sec-header-sub">Data rekaman langsung dari file Data_Deret_waktu_IoT.xlsx</div>
          </div>
        </div>
        """, unsafe_allow_html=True)

        st.markdown(f"""
        <div class="tabel-header-row">
          <span class="tabel-title">Rekaman Mentah Lapangan Kelompok · Mengalir Serentak Menuju Titik Ke-1 sampai 40</span>
          <span class="tabel-count">Live View: 40 Data Terkini</span>
        </div>
        """, unsafe_allow_html=True)

        cols_40 = ['No','Hari','Tanggal','Jam','HST','Soil Moisture (%)','Suhu (°C)','Keterangan','Status Pompa']
        display_rows_40 = 20
        if len(df_timeline_40) > display_rows_40:
            df_table_window_40 = df_timeline_40.iloc[-display_rows_40:].copy()
        else:
            df_table_window_40 = df_timeline_40.copy()

        start_row_40 = df_table_window_40['No'].iloc[0] if not df_table_window_40.empty else 0
        end_row_40 = df_table_window_40['No'].iloc[-1] if not df_table_window_40.empty else 0
        st.markdown(f"<div style='font-size:12px; color:#7ab860; margin-bottom:8px;'>Realtime tabel: menampilkan baris terakhir {start_row_40}–{end_row_40} dari {curr_ptr_40} data.</div>", unsafe_allow_html=True)

        styled_40 = (df_table_window_40[cols_40].style
                     .format({'Soil Moisture (%)': '{:.1f}', 'Suhu (°C)': '{:.1f}'})
                     .map(style_tabel, subset=['Keterangan','Status Pompa']))
        st.dataframe(styled_40, height=320, use_container_width=True, hide_index=True)

        # ── GRAFIK B REAL-TIME (WINDOW BERJALAN 15 DATA LAPANGAN) ──
        st.markdown("""
        <div class="sec-header" style="margin-top:20px;">
          <div class="sec-header-icon">📊</div>
          <div>
            <div class="sec-header-title">Grafik Real-Time — Jendela Bergerak (40 Sampel Lapangan)</div>
            <div class="sec-header-sub">Titik grafik bergeser secara sinkron dengan baris data tabel di atas</div>
          </div>
        </div>
        """, unsafe_allow_html=True)

        st.markdown(f"<div style='font-size:12px; color:#7ab860; margin-bottom:12px;'>Data yang muncul: <strong>{curr_ptr_40}</strong> dari <strong>{max_40}</strong> baris.</div>", unsafe_allow_html=True)

        window_40 = len(x40_base)
        x_w2 = x40_base[-window_40:]
        m_w2 = m40_base[-window_40:]
        s_w2 = s40_base[-window_40:]

        colors_dot = []
        for v in m_w2:
            if v < 60:      colors_dot.append('#f87171')
            elif v <= 70:   colors_dot.append('#5dbe3c')
            else:           colors_dot.append('#60a5fa')

        fig2, ax3 = make_fig(figsize=(14, 4))
        ax3.set_xlabel('Nomor Sampel (Rekaman Lapangan Kelompok)', color='#3d6e30', fontsize=9)
        ax3.set_ylabel('Soil Moisture (%)', color='#5dbe3c', fontsize=10, labelpad=8)
        ax3.plot(x_w2, m_w2, color='#5dbe3c', linewidth=2.2, alpha=0.9, zorder=2)
        ax3.fill_between(x_w2, m_w2, alpha=0.08, color='#5dbe3c')
        ax3.scatter(x_w2, m_w2, c=colors_dot, s=65, zorder=3, edgecolors='#08120a', linewidths=0.8)
        ax3.axhline(60, color='#f87171', linestyle='--', alpha=0.75, linewidth=1.4)
        ax3.axhline(70, color='#60a5fa', linestyle='--', alpha=0.55, linewidth=1.0)
        ax3.tick_params(axis='y', labelcolor='#5dbe3c', labelsize=8)
        ax3.scatter(x_w2[-1], m_w2[-1], color=colors_dot[-1], s=130, zorder=4, edgecolors='#08120a', linewidths=1.5)

        ax4 = ax3.twinx()
        ax4.set_ylabel('Suhu (°C)', color='#f59e0b', fontsize=10, labelpad=8)
        ax4.plot(x_w2, s_w2, color='#f59e0b', linewidth=1.5, alpha=0.75, linestyle='--')
        ax4.scatter(x_w2[-1], s_w2[-1], color='#f59e0b', s=50, zorder=5)
        ax4.tick_params(axis='y', labelcolor='#f59e0b', labelsize=8)
        for sp in ax4.spines.values(): sp.set_edgecolor('#1e3d18')

        fig2.tight_layout(pad=1.5)
        st.pyplot(fig2)
        plt.close(fig2)

        m40_mean = round(float(np.mean(m40_base)), 1)
        s40_mean = round(float(np.mean(s40_base)), 1)
        n_kering = int(sum(1 for v in df_timeline_40['Keterangan'] if v == 'Kering'))
        n_ideal  = int(sum(1 for v in df_timeline_40['Keterangan'] if v == 'Ideal'))
        n_basah  = int(sum(1 for v in df_timeline_40['Keterangan'] if v == 'Basah'))

        st.markdown(f"""
        <div class="chart-legend">
          <div class="legend-item"><div class="legend-dot" style="background:#5dbe3c;"></div>Moisture Ideal</div>
          <div class="legend-item"><div class="legend-dot" style="background:#f87171;"></div>Moisture Kering</div>
          <div class="legend-item"><div class="legend-dot" style="background:#60a5fa;"></div>Moisture Basah</div>
        </div>
        <div class="chart-stat-row">
          <div class="chart-stat-box"><div class="chart-stat-label">Rata-rata Moisture Data 40</div><div class="chart-stat-val">{m40_mean}%</div></div>
          <div class="chart-stat-box"><div class="chart-stat-label">Rata-rata Suhu Data 40</div><div class="chart-stat-val">{s40_mean}°C</div></div>
          <div class="chart-stat-box"><div class="chart-stat-label">Kering / Ideal / Basah</div><div class="chart-stat-val"><span style="color:#f87171;">{n_kering}</span>/<span style="color:#5dbe3c;">{n_ideal}</span>/<span style="color:#60a5fa;">{n_basah}</span></div></div>
        </div>
        """, unsafe_allow_html=True)

# ── Pemanggilan Fungsi Utama ──
render_dashboard(sim_moisture, sim_suhu)